// udp.rs\n// This file implements the UDP handling for the SOCKS inbound connections.\n// Updated to fix the TCP control connection handling.\n\nuse std::net::{TcpStream, UdpSocket};\nuse tokio::task;\n\n/// Keeps the TCP connection alive during UDP sessions.\nfn keep_tcp_alive(tcp_stream: TcpStream) {\n    // Spawn a background task to maintain the TCP connection.\n    task::spawn(async move {\n        let mut buffer = [0; 1024];\n        loop {\n            // Attempt to read from the TCP stream to keep it alive.\n            if let Err(e) = tcp_stream.peek(&mut buffer).await {\n                eprintln!("Failed to keep TCP connection alive: {}", e);\n                break; // Exit the loop on error\n            }\n            // Optionally implement a wait time here to avoid busy looping.\n        }\n    });\n}\n\n// Additional existing code for UDP handling...\n\n